{
  "verses": [
    {
      "n": 26,
      "column": "left",
      "text": "Wiꞥſch teê ar paſchu\nGalwu prett winnu/ ar ſawahm\nbeeaſhm un angſthm preeſch-\nturrmahm Bruzzahm.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Jo wiꞥſch ſawu Waigu\ntauki iſbarro/ un darrahs ſew\nreſuu Wehderu.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Bet wiꞥſch dſihwohs\neekſch iſpohſtiteem Pilſſahteem\nun Nammeem/ kur ne weens\ndſihwo/ ſam nolemts irr par Ak-\nminu Kohpahm buht.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Wiꞥſch ne paliks bag-\ngats/ un wiꞥſa Padohms ne\npaſtahwegs/ un wiꞥſu Laime ne\niſplattifees wirs Semmes.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Wiꞥſch no tahs Tumſi-\nbas ahra ne nahks/ ta Leetma iſ-\nkaltelis wiꞥſa Sarrus/ wiꞥſa * Weeta taps zaur Wehju ais,\ndſihta.\n"
    },
    {
      "n": 31,
      "column": "left",
      "text": "Wiꞥſch ne warrehſ us\nNelectibu patantees / zaur ko\nwiꞥſch peewilts irr/ jo Neleetiba\nbuhs wiꞥſa Alga.\n"
    },
    {
      "n": 32,
      "column": "left",
      "text": "(Wiꞥſa Alga) nahkſees\npreeſch Laika/ un wiꞥſa Sars\nne faltohs.\n"
    },
    {
      "n": 33,
      "column": "left",
      "text": "Wiꞥſch * taps norauts\nta nelaiku Kekkars no Wihna-\nKohka/un nomettihs ſawus See-\ndus ta Efjes-Kohks.\n"
    },
    {
      "n": 34,
      "column": "left",
      "text": "Jo to Blehdneeku Drau-\ndſe paliks weentuta/ un ugguns\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Wiꞥſch apgruhtinaſ\nar Netaifnibu un dſemde G\nturnu/ un winnu * Weh-\ndſenn Wilſibu.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ad atbildeja Ijabſ/\nſazzija:\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Es eſimu da\ntahdas Leetas dſirdejs/ juhs u\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Buhs tad teem uṣp-\nsteem Wahrdeem gann di\nGals? jeb kas pakuhdina tew\natbildeht?\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Bij man ta patt runn-\nta juhs / kad juhsu Dweh-\nmannaſ Dwehfeles Weetā bu\ntu/ bij man prett jums ar Wa-\ndeem turretees/ un mannu G\nwu pahr jums krattiht ?\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Es griibbetu juhs ar ma-\nnu Mutti eespehzinaht/ un ma-\nno Luypu Schehlefchanai\n(juhsu Zahpes) noſlahpebt\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Rad es runnaju/ tad ma-\nnas Zahpes ne rimſt / kad\nmittejoſs/ tad tahs tatschu\nmannim ne noſtabjahs.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Teescham / nu peeſan\nwiꞥſch manni/ tu iſklihdina w\nju mannu Draudſi.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
